import Testing
@testable import AxionCLI

@Suite("SlashPopup windowing")
struct SlashPopupWindowTests {
    private var nonTTYTheme: ChatTheme {
        ChatTheme(profile: .unknown, isTTY: false)
    }

    @Test("P0: scrolled render window keeps absolute candidate numbering")
    func scrolledRenderWindowKeepsAbsoluteNumbering() {
        let items = (1...60).map { index in
            SlashPopupItem(
                kind: .skill(SkillInfo(name: "skill-\(index)", description: "Skill \(index)", aliases: [])),
                matchRange: nil
            )
        }

        let output = SlashPopup.render(
            items: items,
            selectedIndex: 24,
            theme: nonTTYTheme,
            termWidth: 80,
            maxItems: 20,
            startIndex: 5
        )
        let lines = output.split(separator: "\n").map(String.init)

        #expect(lines.count == 20)
        #expect(lines.first?.contains("6.") == true)
        #expect(lines.last?.contains("25.") == true)
        #expect(lines.contains { line in
            line.contains(SlashPopup.selectedMarker)
                && line.contains("25.")
                && line.contains("/skill-25")
        })
    }

    @Test("P1: empty query ranking includes skill alias recent usage")
    func emptyQueryRankingIncludesSkillAliasRecentUsage() {
        let skill = SkillInfo(name: "bmad-quick-dev", description: "Quick dev workflow", aliases: ["qd"])
        let items = SlashPopup.filter(
            query: "/",
            skills: [skill],
            recentUsageCounts: ["/qd": 10]
        )

        #expect(items.first?.kind.displayName == "/bmad-quick-dev")
    }
}

import Testing
@testable import AxionCLI

@Suite("ChatComposer slash popup paging")
struct ChatComposerSlashPopupPagingTests {
    @Test("P0: Down beyond first popup page and Enter submits selected absolute item")
    func downBeyondFirstPageEnterSubmitsAbsoluteSelection() {
        let skills = (1...60).map { index in
            SkillInfo(name: "skill-\(index)", description: "Skill \(index)", aliases: [])
        }
        let expectedItems = SlashPopup.filter(query: "/", skills: skills)
        let expected = expectedItems[20].kind.displayName
        let capture = OutputCapture()
        let reader = MockKeyReader(
            [.printable("/")] + Array(repeating: KeyEvent.down, count: 20) + [.enter]
        )
        var composer = ChatComposer(
            isTTY: true,
            writeStdout: { capture.stdout += $0 },
            writeStderr: { capture.stderr += $0 },
            readLineFn: { nil },
            keyReader: reader
        )
        composer.availableSkills = skills

        let result = composer.readInput(prompt: "> ", continuationPrompt: "...> ")

        #expect(result == expected)
        #expect(capture.stdout.contains("21."))
        #expect(capture.stdout.contains(expected))
    }
}

import Foundation
import Testing
@testable import AxionCLI

@Suite("CommandHistoryStore recent slash usage window")
struct CommandHistoryStoreRecentUsageWindowTests {
    final class RecentUsageMockFile: @unchecked Sendable {
        var content: String?
        init(content: String?) {
            self.content = content
        }
    }

    private func makeStore(initialContent: String?) -> CommandHistoryStore {
        let mock = RecentUsageMockFile(content: initialContent)
        return CommandHistoryStore(
            readFile: { _ in mock.content },
            appendFile: { _, line in mock.content = (mock.content ?? "") + line + "\n" },
            writeFile: { _, content in mock.content = content }
        )
    }

    private func makeJSONLine(_ text: String, ts: String) -> String {
        let obj: [String: String] = ["text": text, "ts": ts]
        let data = try! JSONSerialization.data(withJSONObject: obj, options: .sortedKeys)
        return String(data: data, encoding: .utf8)!
    }

    private func date(_ value: String) -> Date {
        ISO8601DateFormatter().date(from: value)!
    }

    @Test("P1: usage counts include exact cutoff and exclude old or future entries")
    func recentSlashUsageCountsRespectsSevenDayWindow() {
        let content = [
            makeJSONLine("/help", ts: "2026-06-06T00:00:00Z"),
            makeJSONLine("/help", ts: "2026-06-05T23:59:59Z"),
            makeJSONLine("/cost", ts: "2026-06-13T00:00:01Z"),
            makeJSONLine("/model sonnet", ts: "2026-06-13T00:00:00Z")
        ].joined(separator: "\n")
        let store = makeStore(initialContent: content)

        let result = store.recentSlashUsageCounts(
            filePath: "/dev/null",
            now: date("2026-06-13T00:00:00Z"),
            days: 7
        )

        #expect(result["/help"] == 1)
        #expect(result["/model"] == 1)
        #expect(result["/cost"] == nil)
    }
}
